import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import DatePicker, { Calendar, DateObject } from "react-multi-date-picker"
import DatePanel from "react-multi-date-picker/plugins/date_panel";
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import timeGridPlugin from '@fullcalendar/timegrid'



class RoomAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            employeeResult: [], screen: 0, addEmployee: false, editEmployee: false, firstname: "", lastname: "", email: "", employeeid: "", startdate: "", enddate: "", studenttype: ""
        };
    }

    /*
    handleCancelReservation = (event) => {


        if (window.confirm('Are you sure to cancel ' + event.title + " (" + Moment(event.start).format("MM-DD-YYYY") + " " + Moment(event.start).format("hh:mm A") + " - " + Moment(event.end).format("hh:mm A") + ")?")) {
            //this.setState({screen: 0})

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + `deleteScheduleadmin?id=` + event.id, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                var bookedSpaceEvents = []



                response.filter(rec => Moment(rec.end_date_time) >= Moment()).map(reservRec => {
                    bookedSpaceEvents.push({employeeID: reservRec.cyber_user.split("::")[0], employeeName: reservRec.cyber_user.split("::")[1], title: reservRec.room_name, id: reservRec.id, start: reservRec.start_date_time, end: reservRec.end_date_time, comment: reservRec.comment})
                })


                bookedSpaceEvents.sort(function(a,b) {
                    var x = Moment(a.start)
                    var y = Moment(b.start)
                    return x < y ? -1 : x > y ? 1: 0;
                })


                this.setState({bookedSpaceEvents: bookedSpaceEvents})

              })
              .catch(err => {
                console.log(err);
              });

        }


    }


    handleAddEditRoomSubmit = () => {


        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var roomRequest = {room_name: this.state.roomName, employeeID: this.state.roomEmployeeID, employeeName: this.state.roomEmployeeName}

        var backUrl = properties.backend + `addroom`

        if (this.state.editRoom) {
            roomRequest.id = this.state.editRoomID
            backUrl = properties.backend + `editroom`
        }

        fetch(backUrl, {
          "method": "POST",
          headers: headers,
          body: JSON.stringify(roomRequest)

        })
        .then(response => response.json())
        .then(response => {
            this.setState({roomResults: response})
            this.setState({screen: 1})
            this.handleCancelAddEditRoom()
        })
        .catch(err => {
          console.log(err);
        });
    }


    handleCancelAddEditRoom = () => {
        this.setState({addRoom: false})
        this.setState({editRoom: false})
        this.handleCancelRoom()
    }

    handleCancelRoom = () => {
        this.setState({roomName: ""})
        this.setState({employeeRoomCheckbox: false})
        this.setState({roomEmployeeID: ""})
        this.setState({roomEmployeeName: ""})
        this.setState({editRoomID: 0})
    }


    updateEmployeeID = (event) => {
        this.setState({roomEmployeeID: event.target.value})
    }

    updateEmployeeName = (event) => {
        this.setState({roomEmployeeName: event.target.value})
    }

    updateRoomName = (event) => {
        this.setState({roomName: event.target.value})
    }

    handleEmployeeRoomChange = (event) => {
        this.setState({employeeRoomCheckbox: event.target.checked})
        if (!event.target.checked) {
            this.setState({roomEmployeeID: ""})
            this.setState({roomEmployeeName: ""})
        }
    }

    handleDeleteRoom = (item) => {
        if (window.confirm('Are you sure you wish to delete ' + item.room_name)) {
            this.setState({screen: 0})

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + `deleteRoom?id=` + item.id, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({roomResults: response})
                this.setState({screen: 1})
                this.handleCancelAddEditRoom()
                //this.setState({addRoom: false})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });

        }
    }

    handleEditRoom = (editItem) => {
        this.setState({editRoom: true})
        this.setState({addRoom: false})
        this.handleCancelRoom()
        this.setState({roomName: editItem.room_name})
        this.setState({employeeRoomCheckbox: false})
        this.setState({roomEmployeeID: ""})
        if (editItem.owner != null && editItem.owner.length > 0) {
            this.setState({employeeRoomCheckbox: true})
            this.setState({roomEmployeeID: editItem.owner.split("::")[0]})
            this.setState({roomEmployeeName: editItem.owner.split("::")[1]})
        }
        this.setState({editRoomID: editItem.id})
    }  

    handleAddRoom = () => {
        this.setState({addRoom: true})
        this.setState({editRoom: false})
        this.handleCancelRoom()
    }

